#version 300 es
// Pixel Snapper companion — Align Frame (anti-jitter for sprite animations).
//
// Image-edit models never place a character at the exact same spot in every
// sprite-sheet cell, so cropped frames jitter. This shader re-anchors each
// frame: the character's bounding box is centered horizontally and its
// bottom (the feet) is pinned to a shared baseline — the same trick the
// sprite-sheet-creator app does at render time, baked into the asset.
// Translation only, in whole pixels: lossless for pixel art.
//
// Node setup: core GLSLShader, size_mode = from_input.
//   image0 = frame or frame batch (each batch item aligns independently)
//   image1 = the SAME input again (stable copy; pass 0 consumes image0)
//   u_bool0  = lock_feet: pin bbox bottom to the baseline. Enable for
//              walk/attack/idle; DISABLE for jump so the arc survives.
//   u_float0 = baseline margin as a fraction of frame height from the
//              bottom edge (0 -> default 0.06).
//
// Foreground detection: alpha channel if the frame has transparency
// (e.g. after Remove Background), otherwise distance-from-white keying.
// Revealed edges fill with transparent black (alpha mode) or white.
#pragma passes 2

precision highp float;

const int MAXDIM = 4096;
const float WHITE_KEY_DIST = 0.06;

uniform sampler2D u_image0; // pass 0: frame; pass 1: params ping-pong
uniform sampler2D u_image1; // frame (stable)
uniform vec2 u_resolution;
uniform bool u_bool0;       // lock_feet
uniform float u_float0;     // baseline margin fraction (0 -> 0.06)
uniform int u_pass;

in vec2 v_texCoord;
layout(location = 0) out vec4 fragColor0;

bool isFgWhite(vec4 c) {
    vec3 d = abs(c.rgb - vec3(1.0));
    return max(d.r, max(d.g, d.b)) > WHITE_KEY_DIST;
}

void main() {
    ivec2 frag = ivec2(gl_FragCoord.xy);
    ivec2 sz = textureSize(u_image1, 0);
    int W = sz.x;
    int H = sz.y;

    // PASS 0: scan the frame once; write the foreground bbox to pixel (0,0)
    // and the detection mode to pixel (1,0). The bbox is SPECK-TOLERANT: a
    // row/column only counts if it has >= MIN_RUN foreground pixels, so a
    // stray segmentation speck cannot stretch the bbox and mis-anchor.
    if (u_pass == 0) {
        if (frag.y == 0 && frag.x < 2) {
            int transparentCount = 0;
            for (int y = 0; y < MAXDIM; y++) {
                if (y >= H || transparentCount > 0) break;
                for (int x = 0; x < MAXDIM; x++) {
                    if (x >= W) break;
                    if (texelFetch(u_image1, ivec2(x, y), 0).a < 0.5) { transparentCount++; break; }
                }
            }
            bool alphaMode = transparentCount > 0;
            const int MIN_RUN = 3;
            int minX = MAXDIM; int maxX = -1; int minY = MAXDIM; int maxY = -1;
            for (int y = 0; y < MAXDIM; y++) {
                if (y >= H) break;
                int rowCount = 0;
                for (int x = 0; x < MAXDIM; x++) {
                    if (x >= W) break;
                    vec4 c = texelFetch(u_image1, ivec2(x, y), 0);
                    bool fg = alphaMode ? (c.a >= 0.5) : (c.a >= 0.5 && isFgWhite(c));
                    if (fg) rowCount++;
                }
                if (rowCount >= MIN_RUN) { minY = min(minY, y); maxY = max(maxY, y); }
            }
            for (int x = 0; x < MAXDIM; x++) {
                if (x >= W) break;
                int colCount = 0;
                for (int y = 0; y < MAXDIM; y++) {
                    if (y >= H) break;
                    vec4 c = texelFetch(u_image1, ivec2(x, y), 0);
                    bool fg = alphaMode ? (c.a >= 0.5) : (c.a >= 0.5 && isFgWhite(c));
                    if (fg) colCount++;
                }
                if (colCount >= MIN_RUN) { minX = min(minX, x); maxX = max(maxX, x); }
            }
            if (frag.x == 0) {
                if (maxX < 0) {
                    fragColor0 = vec4(0.0); // no foreground -> pass 1 no-ops
                } else {
                    fragColor0 = vec4(float(minX) / 4096.0, float(minY) / 4096.0,
                                      float(maxX) / 4096.0, float(maxY) / 4096.0);
                }
            } else {
                // feet anchor: x-centroid of the character's lowest rows
                // (bbox centers sway with swords/effects; feet stay planted)
                float anchorX = (float(minX) + float(maxX)) * 0.5;
                if (maxX >= 0) {
                    int bandTop = minY + max(int(0.18 * float(maxY - minY + 1)), 6);
                    float sumX = 0.0;
                    float cnt = 0.0;
                    for (int y = 0; y < MAXDIM; y++) {
                        if (y > bandTop || y >= H) break;
                        if (y < minY) continue;
                        for (int x = 0; x < MAXDIM; x++) {
                            if (x >= W) break;
                            vec4 c = texelFetch(u_image1, ivec2(x, y), 0);
                            bool fg = alphaMode ? (c.a >= 0.5) : (c.a >= 0.5 && isFgWhite(c));
                            if (fg) { sumX += float(x); cnt += 1.0; }
                        }
                    }
                    if (cnt > 0.0) anchorX = sumX / cnt;
                }
                fragColor0 = vec4(alphaMode ? 1.0 : 0.0, maxX < 0 ? 0.0 : 1.0,
                                  anchorX / 4096.0, 1.0);
            }
        } else {
            fragColor0 = vec4(0.0);
        }
        return;
    }

    // PASS 1: translate. Texture y=0 is the image BOTTOM (upload flip), so
    // the feet are the bbox's minY and the baseline sits margin*H above 0.
    vec4 bbox = texelFetch(u_image0, ivec2(0, 0), 0) * 4096.0;
    vec4 mode = texelFetch(u_image0, ivec2(1, 0), 0);
    bool alphaMode = mode.x > 0.5;
    bool valid = mode.y > 0.5;

    if (!valid) {
        fragColor0 = texelFetch(u_image1, frag, 0);
        return;
    }

    float margin = u_float0 <= 0.0 ? 0.06 : u_float0;
    float anchorX = mode.z * 4096.0;
    // clamp translations so the bbox stays inside the frame: alignment
    // yields to visibility (never push a sword out of frame)
    float dxf = floor(anchorX - float(W) * 0.5 + 0.5);
    float dxLo = bbox.z - float(W - 1);
    float dxHi = bbox.x;
    int dx = int(dxLo <= dxHi ? clamp(dxf, dxLo, dxHi) : (dxLo + dxHi) * 0.5);
    int dy = 0;
    if (u_bool0) {
        float dyf = floor(bbox.y - margin * float(H) + 0.5);
        float dyLo = bbox.w - float(H - 1);
        float dyHi = bbox.y;
        dy = int(dyLo <= dyHi ? clamp(dyf, dyLo, dyHi) : (dyLo + dyHi) * 0.5);
    }

    ivec2 src = frag + ivec2(dx, dy);
    if (src.x < 0 || src.x >= W || src.y < 0 || src.y >= H) {
        fragColor0 = alphaMode ? vec4(0.0) : vec4(1.0, 1.0, 1.0, 1.0);
    } else {
        fragColor0 = texelFetch(u_image1, src, 0);
    }
}

#version 300 es
// Pixel Snapper companion — Content Zoom (full-bleed normalizer, grid-aware).
//
// Runs on the RAW generated sprite sheet, BEFORE pixel snapping. One shader
// sees every frame at once, so cross-frame decisions are possible: it
// computes a single UNIFORM scale factor sizing the most-constrained
// character to `fill` of its cell, then re-renders the sheet with each
// cell's content scaled and re-anchored onto clean nominal cells.
//
// Works for any grid up to 4x4 (2x2, 3x3, 4x2, ...). Seams between cells
// are ADAPTIVE: each boundary segment is searched per nominal column/row
// band for the line crossing the fewest foreground pixels, so poses that
// spill across nominal midlines keep all their pixels.
//
// Design ledger (each rule exists because a real artifact forced it):
//   scale    = bbox-bounded + shared-ground vertical (asymmetry and
//              under-feet margins must never shrink the sheet)
//   position = feet-band anchor at cell center, CLAMPED in-cell
//              (anti-sway, but alignment yields to visibility)
//   ownership= per-band adaptive seams (raised/lunging weapons stay whole)
//
// Node setup: core GLSLShader, size_mode = from_input.
//   image0 = raw sprite sheet (consumed by pass 0's ping-pong)
//   image1 = the SAME sheet again (stable copy)
//   u_int0   = grid columns (0 -> 2)
//   u_int1   = grid rows    (0 -> 2)
//   u_bool0  = lock_feet: pin every frame's feet to the cell baseline.
//              Enable for grounded animations; DISABLE for jump — frames
//              then rebase to the SHARED GROUND (lowest feet across
//              frames) so arcs survive, proportionally scaled.
//   u_float0 = target fill fraction of the cell (0 -> default 0.90)
//
// Foreground: alpha if the sheet has transparency, else white-keying.
#pragma passes 2

precision highp float;

const int MAXDIM = 4096;
const int MAX_COLS = 4;
const int MAX_ROWS = 4;
const int MAX_CELLS = 16;
const float WHITE_KEY_DIST = 0.06;
const float SEAM_BAND = 0.36;  // search band as a fraction of the cell dim
const float BASELINE = 0.08;   // feet margin as fraction of cell height

uniform sampler2D u_image0; // pass 0: sheet; pass 1: params ping-pong
uniform sampler2D u_image1; // sheet (stable)
uniform vec2 u_resolution;
uniform int u_int0;         // columns
uniform int u_int1;         // rows
uniform bool u_bool0;       // lock_feet
uniform float u_float0;     // fill target (0 -> 0.90)
uniform int u_pass;

in vec2 v_texCoord;
layout(location = 0) out vec4 fragColor0;

int gridCols() { return clamp(u_int0 <= 0 ? 2 : u_int0, 1, MAX_COLS); }
int gridRows() { return clamp(u_int1 <= 0 ? 2 : u_int1, 1, MAX_ROWS); }

bool isFgColor(vec4 c, bool alphaMode) {
    if (alphaMode) return c.a > 0.5;
    vec3 d = abs(c.rgb - vec3(1.0));
    return max(d.r, max(d.g, d.b)) > WHITE_KEY_DIST;
}

// Horizontal seam for boundary k (1..R-1) within nominal column c's band.
int findHSeam(int k, int c, int W, int H, float cellW, float cellH, bool alphaMode) {
    float y0 = float(k) * cellH;
    int yLo = int(y0 - SEAM_BAND * cellH);
    int yHi = int(y0 + SEAM_BAND * cellH);
    int x0 = int(float(c) * cellW);
    int x1 = int(float(c + 1) * cellW);
    float bestCost = 1e9;
    int bestY = int(y0);
    for (int y = 0; y < MAXDIM; y++) {
        if (y < yLo) continue;
        if (y > yHi || y >= H) break;
        float cost = 0.0;
        for (int x = 0; x < MAXDIM; x++) {
            if (x < x0) continue;
            if (x >= x1 || x >= W) break;
            if (isFgColor(texelFetch(u_image1, ivec2(x, y), 0), alphaMode)) cost += 1.0;
        }
        cost += abs(float(y) - y0) * 0.01;
        if (cost < bestCost) { bestCost = cost; bestY = y; }
    }
    return bestY;
}

// Vertical seam for boundary j (1..C-1) within nominal row r's band.
int findVSeam(int j, int r, int W, int H, float cellW, float cellH, bool alphaMode) {
    float x0 = float(j) * cellW;
    int xLo = int(x0 - SEAM_BAND * cellW);
    int xHi = int(x0 + SEAM_BAND * cellW);
    int y0 = int(float(r) * cellH);
    int y1 = int(float(r + 1) * cellH);
    float bestCost = 1e9;
    int bestX = int(x0);
    for (int x = 0; x < MAXDIM; x++) {
        if (x < xLo) continue;
        if (x > xHi || x >= W) break;
        float cost = 0.0;
        for (int y = 0; y < MAXDIM; y++) {
            if (y < y0) continue;
            if (y >= y1 || y >= H) break;
            if (isFgColor(texelFetch(u_image1, ivec2(x, y), 0), alphaMode)) cost += 1.0;
        }
        cost += abs(float(x) - x0) * 0.01;
        if (cost < bestCost) { bestCost = cost; bestX = x; }
    }
    return bestX;
}

void computeSeams(int W, int H, float cellW, float cellH, bool alphaMode,
                  out int hS[12], out int vS[12]) {
    int C = gridCols();
    int R = gridRows();
    for (int i = 0; i < 12; i++) { hS[i] = 0; vS[i] = 0; }
    for (int k = 1; k < MAX_ROWS; k++) {
        if (k >= R) break;
        for (int c = 0; c < MAX_COLS; c++) {
            if (c >= C) break;
            hS[(k - 1) * MAX_COLS + c] = findHSeam(k, c, W, H, cellW, cellH, alphaMode);
        }
    }
    for (int j = 1; j < MAX_COLS; j++) {
        if (j >= C) break;
        for (int r = 0; r < MAX_ROWS; r++) {
            if (r >= R) break;
            vS[(j - 1) * MAX_ROWS + r] = findVSeam(j, r, W, H, cellW, cellH, alphaMode);
        }
    }
}

// Cell index (texture space: row 0 = bottom band) that owns pixel p.
int ownerOf(ivec2 p, float cellW, float cellH, int hS[12], int vS[12]) {
    int C = gridCols();
    int R = gridRows();
    int cNom = clamp(int(float(p.x) / cellW), 0, C - 1);
    int r = 0;
    for (int k = 1; k < MAX_ROWS; k++) {
        if (k >= R) break;
        if (p.y > hS[(k - 1) * MAX_COLS + cNom]) r = k;
    }
    int c = 0;
    for (int j = 1; j < MAX_COLS; j++) {
        if (j >= C) break;
        if (p.x >= vS[(j - 1) * MAX_ROWS + r]) c = j;
    }
    return r * C + c;
}

float cellBaseOf(int cell, int hS[12]) {
    int C = gridCols();
    int r = cell / C;
    int c = cell - r * C;
    return r == 0 ? 0.0 : float(hS[(r - 1) * MAX_COLS + c] + 1);
}

void main() {
    ivec2 frag = ivec2(gl_FragCoord.xy);
    ivec2 sz = textureSize(u_image1, 0);
    int W = sz.x;
    int H = sz.y;
    int C = gridCols();
    int R = gridRows();
    float cellW = float(W) / float(C);
    float cellH = float(H) / float(R);
    int nCells = C * R;

    // PASS 0: params.
    //   row 0: (0,0)=mode/dims, (1..12,0)=hSeams, (13..24,0)=vSeams
    //   row 1: per-cell bboxes   row 2: per-cell feet anchors
    if (u_pass == 0) {
        bool metaRow = frag.y == 0 && frag.x < 25;
        bool bboxRow = frag.y == 1 && frag.x < nCells;
        bool anchRow = frag.y == 2 && frag.x < nCells;
        if (metaRow || bboxRow || anchRow) {
            bool alphaMode = false;
            for (int y = 0; y < MAXDIM; y++) {
                if (y >= H || alphaMode) break;
                for (int x = 0; x < MAXDIM; x++) {
                    if (x >= W) break;
                    if (texelFetch(u_image1, ivec2(x, y), 0).a < 0.5) { alphaMode = true; break; }
                }
            }
            int hS[12]; int vS[12];
            computeSeams(W, H, cellW, cellH, alphaMode, hS, vS);

            if (metaRow) {
                if (frag.x == 0) {
                    fragColor0 = vec4(alphaMode ? 1.0 : 0.0, float(C) / 16.0, float(R) / 16.0, 1.0);
                } else if (frag.x <= 12) {
                    fragColor0 = vec4(float(hS[frag.x - 1]) / 4096.0, 0.0, 0.0, 1.0);
                } else {
                    fragColor0 = vec4(float(vS[frag.x - 13]) / 4096.0, 0.0, 0.0, 1.0);
                }
                return;
            }

            int cell = frag.x;
            int minX = MAXDIM; int maxX = -1; int minY = MAXDIM; int maxY = -1;
            for (int y = 0; y < MAXDIM; y++) {
                if (y >= H) break;
                for (int x = 0; x < MAXDIM; x++) {
                    if (x >= W) break;
                    ivec2 p = ivec2(x, y);
                    if (ownerOf(p, cellW, cellH, hS, vS) != cell) continue;
                    if (isFgColor(texelFetch(u_image1, p, 0), alphaMode)) {
                        minX = min(minX, x); maxX = max(maxX, x);
                        minY = min(minY, y); maxY = max(maxY, y);
                    }
                }
            }
            if (maxX < 0) { fragColor0 = vec4(0.0); return; }

            if (bboxRow) {
                fragColor0 = vec4(float(minX) / 4096.0, float(minY) / 4096.0,
                                  float(maxX) / 4096.0, float(maxY) / 4096.0);
                return;
            }
            // feet anchor: x-centroid of the character's lowest rows
            int bandTop = minY + max(int(0.18 * float(maxY - minY + 1)), 6);
            float sumX = 0.0;
            float cnt = 0.0;
            for (int y = 0; y < MAXDIM; y++) {
                if (y > bandTop || y >= H) break;
                if (y < minY) continue;
                for (int x = 0; x < MAXDIM; x++) {
                    if (x >= W) break;
                    ivec2 p = ivec2(x, y);
                    if (ownerOf(p, cellW, cellH, hS, vS) != cell) continue;
                    if (isFgColor(texelFetch(u_image1, p, 0), alphaMode)) {
                        sumX += float(x); cnt += 1.0;
                    }
                }
            }
            float anchorX = cnt > 0.0 ? sumX / cnt : (float(minX) + float(maxX)) * 0.5;
            fragColor0 = vec4(anchorX / 4096.0, 1.0, 0.0, 1.0);
            return;
        }
        fragColor0 = vec4(0.0);
        return;
    }

    // PASS 1: re-render onto clean nominal cells with one uniform scale.
    vec4 meta = texelFetch(u_image0, ivec2(0, 0), 0);
    bool alphaMode = meta.x > 0.5;
    float fill = u_float0 <= 0.0 ? 0.90 : u_float0;
    vec4 blank = alphaMode ? vec4(0.0) : vec4(1.0, 1.0, 1.0, 1.0);

    int hS[12]; int vS[12];
    for (int i = 0; i < 12; i++) {
        hS[i] = int(texelFetch(u_image0, ivec2(1 + i, 0), 0).r * 4096.0 + 0.5);
        vS[i] = int(texelFetch(u_image0, ivec2(13 + i, 0), 0).r * 4096.0 + 0.5);
    }

    vec4 bboxes[MAX_CELLS];
    float anchors[MAX_CELLS];
    bool valid[MAX_CELLS];
    bool anyValid = false;
    float ground = 1e9;
    for (int i = 0; i < MAX_CELLS; i++) {
        if (i >= nCells) { valid[i] = false; continue; }
        bboxes[i] = texelFetch(u_image0, ivec2(i, 1), 0) * 4096.0;
        vec4 av = texelFetch(u_image0, ivec2(i, 2), 0);
        anchors[i] = av.x * 4096.0;
        valid[i] = av.y > 0.5 && bboxes[i].z >= bboxes[i].x;
        if (valid[i]) {
            anyValid = true;
            ground = min(ground, bboxes[i].y - cellBaseOf(i, hS));
        }
    }
    if (!anyValid) { fragColor0 = texelFetch(u_image1, frag, 0); return; }

    float s = 1e9;
    for (int i = 0; i < MAX_CELLS; i++) {
        if (i >= nCells || !valid[i]) continue;
        float bw = bboxes[i].z - bboxes[i].x + 1.0;
        float vExt = u_bool0 ? (bboxes[i].w - bboxes[i].y + 1.0)
                             : max(bboxes[i].w - cellBaseOf(i, hS) - ground + 1.0, 1.0);
        s = min(s, fill * min(cellW / bw, cellH / vExt));
    }
    s = clamp(s, 0.25, 6.0);

    int col = clamp(int(float(frag.x) / cellW), 0, C - 1);
    int tRow = clamp(int(float(frag.y) / cellH), 0, R - 1);
    int i = tRow * C + col;
    if (!valid[i]) { fragColor0 = blank; return; }

    vec2 cellDst = vec2(float(col) * cellW, float(tRow) * cellH);
    float srcBase = cellBaseOf(i, hS);

    float pad = 0.5 * (1.0 - fill) * cellW;
    float dstLo = cellDst.x + pad + s * (anchors[i] - bboxes[i].x);
    float dstHi = cellDst.x + cellW - pad - s * (bboxes[i].z - anchors[i]);
    float anchorDstX = dstLo <= dstHi
        ? clamp(cellDst.x + cellW * 0.5, dstLo, dstHi)
        : (dstLo + dstHi) * 0.5;
    float srcX = anchors[i] + (float(frag.x) - anchorDstX) / s;

    float feetDstY = cellDst.y + BASELINE * cellH;
    float srcY = u_bool0
        ? bboxes[i].y + (float(frag.y) - feetDstY) / s
        : srcBase + ground + (float(frag.y) - feetDstY) / s;

    ivec2 src = ivec2(int(srcX + 0.5), int(srcY + 0.5));
    if (src.x < 0 || src.x >= W || src.y < 0 || src.y >= H
        || ownerOf(src, cellW, cellH, hS, vS) != i) {
        fragColor0 = blank;
    } else {
        fragColor0 = texelFetch(u_image1, src, 0);
    }
}

#version 300 es
// Pixel Snapper companion — Alpha Crisp.
//
// Hardens a soft background-removal alpha into a pixel-art-ready binary
// cutout. Segmentation masks can bleed across empty background (e.g.
// bridging two vertically adjacent characters), so pass 0 INTERSECTS the
// mask with actual color content: opaque requires mask foreground AND a
// non-background pixel. Pass 1 is a 5x5 majority cleanup that kills
// leftover specks and refills small enclosed highlights (pixels within
// ~2px of colored content). Limitation: large interior regions the exact
// color of the background stay transparent.
//
// Node setup: core GLSLShader, size_mode = from_input.
//   image0 = RGBA image (e.g. BiRefNet output; consumed by ping-pong)
//   image1 = the SAME image again (stable copy)
//   u_float0 = alpha threshold (0 -> default 0.5)
#pragma passes 2

precision highp float;

const float WHITE_KEY_DIST = 0.06;

uniform sampler2D u_image0; // pass 0: source; pass 1: intersected ping-pong
uniform sampler2D u_image1; // source (stable)
uniform vec2 u_resolution;
uniform float u_float0;
uniform int u_pass;

in vec2 v_texCoord;
layout(location = 0) out vec4 fragColor0;

bool notBackground(vec3 rgb) {
    vec3 d = abs(rgb - vec3(1.0));
    return max(d.r, max(d.g, d.b)) > WHITE_KEY_DIST;
}

void main() {
    ivec2 p = ivec2(gl_FragCoord.xy);
    ivec2 sz = textureSize(u_image1, 0);
    float t = u_float0 <= 0.0 ? 0.5 : u_float0;
    vec4 src = texelFetch(u_image1, p, 0);

    // PASS 0: mask AND color content
    if (u_pass == 0) {
        bool opaque = src.a > t && notBackground(src.rgb);
        fragColor0 = vec4(src.rgb, opaque ? 1.0 : 0.0);
        return;
    }

    // PASS 1: majority cleanup on the intersected alpha
    int n = 0;
    for (int dy = -2; dy <= 2; dy++) {
        for (int dx = -2; dx <= 2; dx++) {
            ivec2 q = p + ivec2(dx, dy);
            if (q.x < 0 || q.y < 0 || q.x >= sz.x || q.y >= sz.y) continue;
            if (texelFetch(u_image0, q, 0).a > 0.5) n++;
        }
    }
    bool prevOpaque = texelFetch(u_image0, p, 0).a > 0.5;
    bool opaque = (prevOpaque && n >= 6) || n >= 20;
    fragColor0 = vec4(src.rgb, opaque ? 1.0 : 0.0);
}

#version 300 es
// Pixel Snapper companion — Align Frame (anti-jitter for sprite animations).
//
// Image-edit models never place a character at the exact same spot in every
// sprite-sheet cell, so cropped frames jitter. This shader re-anchors each
// frame: the character's bounding box is centered horizontally and its
// bottom (the feet) is pinned to a shared baseline — the same trick the
// sprite-sheet-creator app does at render time, baked into the asset.
// Translation only, in whole pixels: lossless for pixel art.
//
// Node setup: core GLSLShader, size_mode = from_input.
//   image0 = frame or frame batch (each batch item aligns independently)
//   image1 = the SAME input again (stable copy; pass 0 consumes image0)
//   u_bool0  = lock_feet: pin bbox bottom to the baseline. Enable for
//              walk/attack/idle; DISABLE for jump so the arc survives.
//   u_float0 = baseline margin as a fraction of frame height from the
//              bottom edge (0 -> default 0.06).
//
// Foreground detection: alpha channel if the frame has transparency
// (e.g. after Remove Background), otherwise distance-from-white keying.
// Revealed edges fill with transparent black (alpha mode) or white.
#pragma passes 2

precision highp float;

const int MAXDIM = 4096;
const float WHITE_KEY_DIST = 0.06;

uniform sampler2D u_image0; // pass 0: frame; pass 1: params ping-pong
uniform sampler2D u_image1; // frame (stable)
uniform vec2 u_resolution;
uniform bool u_bool0;       // lock_feet
uniform float u_float0;     // baseline margin fraction (0 -> 0.06)
uniform int u_pass;

in vec2 v_texCoord;
layout(location = 0) out vec4 fragColor0;

bool isFgWhite(vec4 c) {
    vec3 d = abs(c.rgb - vec3(1.0));
    return max(d.r, max(d.g, d.b)) > WHITE_KEY_DIST;
}

void main() {
    ivec2 frag = ivec2(gl_FragCoord.xy);
    ivec2 sz = textureSize(u_image1, 0);
    int W = sz.x;
    int H = sz.y;

    // PASS 0: scan the frame once; write the foreground bbox to pixel (0,0)
    // and the detection mode to pixel (1,0). The bbox is SPECK-TOLERANT: a
    // row/column only counts if it has >= MIN_RUN foreground pixels, so a
    // stray segmentation speck cannot stretch the bbox and mis-anchor.
    if (u_pass == 0) {
        if (frag.y == 0 && frag.x < 2) {
            int transparentCount = 0;
            for (int y = 0; y < MAXDIM; y++) {
                if (y >= H || transparentCount > 0) break;
                for (int x = 0; x < MAXDIM; x++) {
                    if (x >= W) break;
                    if (texelFetch(u_image1, ivec2(x, y), 0).a < 0.5) { transparentCount++; break; }
                }
            }
            bool alphaMode = transparentCount > 0;
            const int MIN_RUN = 3;
            int minX = MAXDIM; int maxX = -1; int minY = MAXDIM; int maxY = -1;
            for (int y = 0; y < MAXDIM; y++) {
                if (y >= H) break;
                int rowCount = 0;
                for (int x = 0; x < MAXDIM; x++) {
                    if (x >= W) break;
                    vec4 c = texelFetch(u_image1, ivec2(x, y), 0);
                    bool fg = alphaMode ? (c.a >= 0.5) : (c.a >= 0.5 && isFgWhite(c));
                    if (fg) rowCount++;
                }
                if (rowCount >= MIN_RUN) { minY = min(minY, y); maxY = max(maxY, y); }
            }
            for (int x = 0; x < MAXDIM; x++) {
                if (x >= W) break;
                int colCount = 0;
                for (int y = 0; y < MAXDIM; y++) {
                    if (y >= H) break;
                    vec4 c = texelFetch(u_image1, ivec2(x, y), 0);
                    bool fg = alphaMode ? (c.a >= 0.5) : (c.a >= 0.5 && isFgWhite(c));
                    if (fg) colCount++;
                }
                if (colCount >= MIN_RUN) { minX = min(minX, x); maxX = max(maxX, x); }
            }
            if (frag.x == 0) {
                if (maxX < 0) {
                    fragColor0 = vec4(0.0); // no foreground -> pass 1 no-ops
                } else {
                    fragColor0 = vec4(float(minX) / 4096.0, float(minY) / 4096.0,
                                      float(maxX) / 4096.0, float(maxY) / 4096.0);
                }
            } else {
                // feet anchor: x-centroid of the character's lowest rows
                // (bbox centers sway with swords/effects; feet stay planted)
                float anchorX = (float(minX) + float(maxX)) * 0.5;
                if (maxX >= 0) {
                    int bandTop = minY + max(int(0.18 * float(maxY - minY + 1)), 6);
                    float sumX = 0.0;
                    float cnt = 0.0;
                    for (int y = 0; y < MAXDIM; y++) {
                        if (y > bandTop || y >= H) break;
                        if (y < minY) continue;
                        for (int x = 0; x < MAXDIM; x++) {
                            if (x >= W) break;
                            vec4 c = texelFetch(u_image1, ivec2(x, y), 0);
                            bool fg = alphaMode ? (c.a >= 0.5) : (c.a >= 0.5 && isFgWhite(c));
                            if (fg) { sumX += float(x); cnt += 1.0; }
                        }
                    }
                    if (cnt > 0.0) anchorX = sumX / cnt;
                }
                fragColor0 = vec4(alphaMode ? 1.0 : 0.0, maxX < 0 ? 0.0 : 1.0,
                                  anchorX / 4096.0, 1.0);
            }
        } else {
            fragColor0 = vec4(0.0);
        }
        return;
    }

    // PASS 1: translate. Texture y=0 is the image BOTTOM (upload flip), so
    // the feet are the bbox's minY and the baseline sits margin*H above 0.
    vec4 bbox = texelFetch(u_image0, ivec2(0, 0), 0) * 4096.0;
    vec4 mode = texelFetch(u_image0, ivec2(1, 0), 0);
    bool alphaMode = mode.x > 0.5;
    bool valid = mode.y > 0.5;

    if (!valid) {
        fragColor0 = texelFetch(u_image1, frag, 0);
        return;
    }

    float margin = u_float0 <= 0.0 ? 0.06 : u_float0;
    float anchorX = mode.z * 4096.0;
    // clamp translations so the bbox stays inside the frame: alignment
    // yields to visibility (never push a sword out of frame)
    float dxf = floor(anchorX - float(W) * 0.5 + 0.5);
    float dxLo = bbox.z - float(W - 1);
    float dxHi = bbox.x;
    int dx = int(dxLo <= dxHi ? clamp(dxf, dxLo, dxHi) : (dxLo + dxHi) * 0.5);
    int dy = 0;
    if (u_bool0) {
        float dyf = floor(bbox.y - margin * float(H) + 0.5);
        float dyLo = bbox.w - float(H - 1);
        float dyHi = bbox.y;
        dy = int(dyLo <= dyHi ? clamp(dyf, dyLo, dyHi) : (dyLo + dyHi) * 0.5);
    }

    ivec2 src = frag + ivec2(dx, dy);
    if (src.x < 0 || src.x >= W || src.y < 0 || src.y >= H) {
        fragColor0 = alphaMode ? vec4(0.0) : vec4(1.0, 1.0, 1.0, 1.0);
    } else {
        fragColor0 = texelFetch(u_image1, src, 0);
    }
}

#version 300 es
// Pixel Snapper (native GLSL) — stage 1/3: k-means color quantization.
//
// Node setup: core GLSLShader, size_mode = from_input.
//   image0 = source image (becomes the ping-pong buffer after pass 0)
//   image1 = the SAME source image again (stable copy for the final pass)
//   u_int0 = color_count K (2..32, 0 -> 16)
// Outputs:
//   IMAGE0 = quantized image (every pixel snapped to its nearest centroid)
//   IMAGE1 = palette stripes (K vertical bands; stage 3 samples these)
//
// Working state lives in the ping-pong buffer: row 0 cols 0..K-1 hold the
// centroids, rows 1..GRID hold a GRID x GRID downsample of the source used
// for the k-means iterations.
#pragma passes 13

precision highp float;

const int MAX_K = 32;
const int GRID = 64;        // cached source samples per axis
const int NUM_PASSES = 13;  // keep equal to `#pragma passes` above

uniform sampler2D u_image0; // pass 0: source; pass 1+: ping-pong buffer
uniform sampler2D u_image1; // source (stable across passes)
uniform vec2 u_resolution;
uniform int u_int0;         // color_count K
uniform int u_pass;

in vec2 v_texCoord;
layout(location = 0) out vec4 fragColor0;
layout(location = 1) out vec4 fragColor1;

int kColors() { return clamp(u_int0 <= 0 ? 16 : u_int0, 2, MAX_K); }

vec3 readCentroid(int i) { return texelFetch(u_image0, ivec2(i, 0), 0).rgb; }
vec3 readCache(int sx, int sy) { return texelFetch(u_image0, ivec2(sx, sy + 1), 0).rgb; }

int nearestCentroid(vec3 p, int k) {
    float best = 1e9;
    int bi = 0;
    for (int j = 0; j < MAX_K; j++) {
        if (j >= k) break;
        vec3 d = p - readCentroid(j);
        float dist = dot(d, d);
        if (dist < best) { best = dist; bi = j; }
    }
    return bi;
}

void main() {
    int k = kColors();
    ivec2 frag = ivec2(gl_FragCoord.xy);

    // PASS 0: cache a GRID x GRID downsample of the source (rows 1..GRID).
    if (u_pass == 0) {
        if (frag.y >= 1 && frag.y <= GRID && frag.x < GRID) {
            vec2 uv = (vec2(float(frag.x), float(frag.y - 1)) + 0.5) / float(GRID);
            fragColor0 = vec4(texture(u_image0, uv).rgb, 1.0);
        } else {
            fragColor0 = vec4(0.0, 0.0, 0.0, 1.0);
        }
        fragColor1 = vec4(0.0, 0.0, 0.0, 1.0);
        return;
    }

    // PASS 1: farthest-point seeding. Fragment (j, 0) replays the greedy
    // maximin sequence over the cached samples and writes centroid j.
    // Deterministic, and unlike random scatter it will not start two
    // centroids inside the same dominant color.
    if (u_pass == 1) {
        if (frag.y == 0 && frag.x < k) {
            vec3 chosen[MAX_K];
            chosen[0] = readCache(0, 0);
            for (int s = 1; s < MAX_K; s++) {
                if (s > frag.x) break;
                float bestD = -1.0;
                vec3 bestP = chosen[0];
                for (int sy = 0; sy < GRID; sy++) {
                    for (int sx = 0; sx < GRID; sx++) {
                        vec3 p = readCache(sx, sy);
                        float dmin = 1e9;
                        for (int t = 0; t < MAX_K; t++) {
                            if (t >= s) break;
                            vec3 d = p - chosen[t];
                            dmin = min(dmin, dot(d, d));
                        }
                        if (dmin > bestD) { bestD = dmin; bestP = p; }
                    }
                }
                chosen[s] = bestP;
            }
            fragColor0 = vec4(chosen[frag.x], 1.0);
        } else {
            fragColor0 = texelFetch(u_image0, frag, 0);
        }
        fragColor1 = vec4(0.0, 0.0, 0.0, 1.0);
        return;
    }

    // PASSES 2..N-2: one k-means iteration over the cached samples.
    if (u_pass < NUM_PASSES - 1) {
        if (frag.y == 0 && frag.x < k) {
            int c = frag.x;
            vec3 sum = vec3(0.0);
            float cnt = 0.0;
            for (int sy = 0; sy < GRID; sy++) {
                for (int sx = 0; sx < GRID; sx++) {
                    vec3 p = readCache(sx, sy);
                    if (nearestCentroid(p, k) == c) { sum += p; cnt += 1.0; }
                }
            }
            fragColor0 = vec4(cnt > 0.0 ? sum / cnt : readCentroid(c), 1.0);
        } else {
            fragColor0 = texelFetch(u_image0, frag, 0);
        }
        fragColor1 = vec4(0.0, 0.0, 0.0, 1.0);
        return;
    }

    // FINAL PASS: map every source pixel to its nearest centroid, and
    // emit the palette as K vertical stripes on IMAGE1.
    vec3 src = texture(u_image1, v_texCoord).rgb;
    fragColor0 = vec4(readCentroid(nearestCentroid(src, k)), 1.0);
    int band = clamp(int(v_texCoord.x * float(k)), 0, k - 1);
    fragColor1 = vec4(readCentroid(band), 1.0);
}

#version 300 es
// Pixel Snapper (native GLSL) — stage 2/3: grid detection.
//
// Node setup: core GLSLShader, size_mode = custom, width 4096, height 8.
//   image0 = quantized image from stage 1 (becomes ping-pong after pass 0)
//   image1 = the SAME quantized image again (stable copy)
//   u_int0 = pixel_size override (0 = auto-detect)
// Output:
//   IMAGE0 = params texture; every pixel holds
//            (step_x, phase_x, step_y, phase_y) / 4096 as float RGBA.
//
// Method — a GLSL port of the Python estimator (jitter-robust, unlike
// autocorrelation which locks onto harmonics):
//   gradient profiles per axis -> strong local peaks (plateau-tolerant,
//   min 4px apart) -> median peak spacing = art-pixel size ->
//   phase = offset whose grid lines collect the most gradient energy.
// The whole estimator runs sequentially in one fragment of pass 1.
//
// Ping-pong layout: row 0 = column profile, row 1 = row profile,
// row 4 px 0 = resolved params. Supports sources up to 4096 px per side.
#pragma passes 3

precision highp float;

const int MAXDIM = 4096;
const int MAX_DIFFS = 700;
const float PEAK_THRESHOLD = 0.2;  // fraction of profile max
const int PEAK_MIN_DIST = 4;       // matches peak_distance_filter
const float MAX_STEP_RATIO = 1.8;

uniform sampler2D u_image0; // pass 0: quantized source; pass 1+: ping-pong
uniform sampler2D u_image1; // quantized source (stable)
uniform vec2 u_resolution;
uniform int u_int0;         // pixel_size override, 0 = auto
uniform int u_pass;

in vec2 v_texCoord;
layout(location = 0) out vec4 fragColor0;

float grayAt(ivec2 p) {
    vec3 c = texelFetch(u_image1, p, 0).rgb;
    return dot(c, vec3(0.299, 0.587, 0.114));
}

float prof(int x, int axis) { return texelFetch(u_image0, ivec2(x, axis), 0).r; }

bool isPeak(int i, int axis, float threshold) {
    float v = prof(i, axis);
    return v > threshold && v >= prof(i - 1, axis) && v > prof(i + 1, axis);
}

// Number of kept-peak spacings <= v (v < 0: count all spacings).
// Kept peaks follow the Python rule: first strong peak always kept, later
// ones only when > PEAK_MIN_DIST-1 past the last kept one.
int countSpacings(int axis, int n, float threshold, int v) {
    int count = 0;
    int last = -1;
    for (int i = 1; i < MAXDIM; i++) {
        if (i >= n - 1) break;
        if (isPeak(i, axis, threshold)) {
            if (last < 0) {
                last = i;
            } else if (i - last > PEAK_MIN_DIST - 1) {
                if (v < 0 || i - last <= v) count++;
                last = i;
            }
        }
    }
    return count;
}

// Median peak spacing of one axis profile; 0.0 if no reliable estimate.
// Arrayless on purpose: large local arrays miscompiled in fragment shaders.
float estimateStep(int axis, int n) {
    float maxVal = 0.0;
    for (int i = 0; i < MAXDIM; i++) {
        if (i >= n) break;
        maxVal = max(maxVal, prof(i, axis));
    }
    if (maxVal <= 0.0) return 0.0;
    float threshold = maxVal * PEAK_THRESHOLD;

    int m = countSpacings(axis, n, threshold, -1);
    if (m < 1) return 0.0;

    // upper median = (m/2 + 1)-th smallest spacing = smallest value v with
    // count(spacings <= v) >= m/2 + 1  (spacings are integers)
    int target = m / 2 + 1;
    for (int v = PEAK_MIN_DIST; v <= MAX_DIFFS; v++) {
        if (countSpacings(axis, n, threshold, v) >= target) return float(v);
    }
    return 0.0;
}

// Offset in [0, step) whose grid lines collect the most gradient energy.
float bestPhase(float st, int axis, int n) {
    int sti = max(int(st + 0.5), 1);
    float bestScore = -1.0;
    int bestOff = 0;
    for (int off = 0; off < 512; off++) {
        if (off >= sti) break;
        float s = 0.0;
        for (int j = 0; j < MAXDIM; j++) {
            int pos = int(float(off) + float(j) * st + 0.5);
            if (pos >= n) break;
            s += prof(pos, axis);
        }
        if (s > bestScore) { bestScore = s; bestOff = off; }
    }
    return float(bestOff);
}

void main() {
    ivec2 frag = ivec2(gl_FragCoord.xy);
    ivec2 sz = textureSize(u_image1, 0);
    int W = sz.x;
    int H = sz.y;

    // PASS 0: summed absolute central-difference gradients.
    if (u_pass == 0) {
        float v = 0.0;
        if (frag.y == 0 && frag.x >= 1 && frag.x < min(W - 1, MAXDIM)) {
            for (int y = 0; y < MAXDIM; y++) {
                if (y >= H) break;
                v += abs(grayAt(ivec2(frag.x + 1, y)) - grayAt(ivec2(frag.x - 1, y)));
            }
        } else if (frag.y == 1 && frag.x >= 1 && frag.x < min(H - 1, MAXDIM)) {
            for (int x = 0; x < MAXDIM; x++) {
                if (x >= W) break;
                v += abs(grayAt(ivec2(x, frag.x + 1)) - grayAt(ivec2(x, frag.x - 1)));
            }
        }
        fragColor0 = vec4(v, 0.0, 0.0, 1.0);
        return;
    }

    // PASS 1: full estimator in one fragment -> row 4 pixel 0.
    if (u_pass == 1) {
        if (frag.y == 4 && frag.x == 0) {
            float sx = estimateStep(0, W);
            float sy = estimateStep(1, H);

            if (u_int0 > 0) {
                sx = float(u_int0); sy = float(u_int0);
            } else if (sx <= 0.0 && sy <= 0.0) {
                sx = max(float(min(W, H)) / 64.0, 1.0); sy = sx;
            } else if (sx <= 0.0) { sx = sy; }
            else if (sy <= 0.0) { sy = sx; }
            else {
                float ratio = max(sx / sy, sy / sx);
                if (ratio > MAX_STEP_RATIO) { sx = min(sx, sy); sy = sx; }
                else { sx = (sx + sy) * 0.5; sy = sx; }
            }

            float phX = bestPhase(sx, 0, W);
            float phY = bestPhase(sy, 1, H);
            fragColor0 = vec4(sx / 4096.0, phX / 4096.0, sy / 4096.0, phY / 4096.0);
        } else {
            fragColor0 = texelFetch(u_image0, frag, 0);
        }
        return;
    }

    // FINAL PASS: plain copy — profiles stay in rows 0/1, params in row 4.
    // Consumers texelFetch absolute rows (upload/readback flips are
    // symmetric, so GL row addressing survives node hops).
    fragColor0 = texelFetch(u_image0, frag, 0);
}

#version 300 es
// Pixel Snapper (native GLSL) — stage 3/3: snap to grid (majority vote).
//
// Node setup: core GLSLShader, size_mode = from_input.
//   image0 = quantized image from stage 1 (becomes ping-pong after pass 0)
//   image1 = params texture from stage 2
//   image2 = palette stripes from stage 1 (IMAGE1 output)
//   u_int0 = color_count K (same value as stage 1)
// Output:
//   IMAGE0 = snapped image at full resolution: every grid cell painted
//            with its majority color (majority vote preserves dithering).
//
// Pass 0 computes each cell's winning palette color into the top-left
// corner of the buffer (one pixel per cell); pass 1 paints every output
// pixel by looking up its cell. For a true native-resolution asset,
// downscale this output by 1/pixel_size with nearest-neighbor.
#pragma passes 2

precision highp float;

const int MAX_K = 32;
const int MAX_CELL = 128; // max art-pixel size in source px

uniform sampler2D u_image0; // pass 0: quantized source; pass 1: cell map
uniform sampler2D u_image1; // params texture (step/phase, /4096)
uniform sampler2D u_image2; // palette stripes
uniform vec2 u_resolution;
uniform int u_int0;         // color_count K
uniform int u_pass;

in vec2 v_texCoord;
layout(location = 0) out vec4 fragColor0;

int kColors() { return clamp(u_int0 <= 0 ? 16 : u_int0, 2, MAX_K); }

vec3 paletteColor(int i, int k) {
    return texture(u_image2, vec2((float(i) + 0.5) / float(k), 0.5)).rgb;
}

int nearestPalette(vec3 p, int k) {
    float best = 1e9;
    int bi = 0;
    for (int j = 0; j < MAX_K; j++) {
        if (j >= k) break;
        vec3 d = p - paletteColor(j, k);
        float dist = dot(d, d);
        if (dist < best) { best = dist; bi = j; }
    }
    return bi;
}

void main() {
    ivec2 frag = ivec2(gl_FragCoord.xy);
    int k = kColors();
    vec4 params = texelFetch(u_image1, ivec2(0, 4), 0) * 4096.0;
    float stepX = max(params.x, 1.0);
    float phX = params.y;
    float stepY = max(params.z, 1.0);
    float phY = params.w;
    int W = int(u_resolution.x);
    int H = int(u_resolution.y);

    // Pixel x belongs to cell floor((x - phase) / step); cell ids are
    // shifted so the first in-image cell is 0.
    int cx0 = int(floor((0.0 - phX) / stepX));
    int cy0 = int(floor((0.0 - phY) / stepY));

    if (u_pass == 0) {
        // Fragment (cx, cy) = majority palette color of that cell.
        int cellX = frag.x + cx0;
        int cellY = frag.y + cy0;
        float xs = phX + float(cellX) * stepX;
        float xe = xs + stepX;
        float ys = phY + float(cellY) * stepY;
        float ye = ys + stepY;
        int x0 = max(int(ceil(xs - 0.0001)), 0);
        int x1 = min(int(ceil(xe - 0.0001)), W);
        int y0 = max(int(ceil(ys - 0.0001)), 0);
        int y1 = min(int(ceil(ye - 0.0001)), H);

        if (x0 >= x1 || y0 >= y1 || x0 >= W || y0 >= H) {
            fragColor0 = vec4(0.0, 0.0, 0.0, 1.0);
            return;
        }

        int counts[MAX_K];
        for (int j = 0; j < MAX_K; j++) counts[j] = 0;

        for (int dy = 0; dy < MAX_CELL; dy++) {
            int y = y0 + dy;
            if (y >= y1) break;
            for (int dx = 0; dx < MAX_CELL; dx++) {
                int x = x0 + dx;
                if (x >= x1) break;
                vec3 p = texelFetch(u_image0, ivec2(x, y), 0).rgb;
                counts[nearestPalette(p, k)]++;
            }
        }

        int bestCount = -1;
        int bestId = 0;
        for (int j = 0; j < MAX_K; j++) {
            if (j >= k) break;
            if (counts[j] > bestCount) { bestCount = counts[j]; bestId = j; }
        }
        fragColor0 = vec4(paletteColor(bestId, k), 1.0);
        return;
    }

    // PASS 1: paint every pixel with its cell's winning color.
    int cellX = int(floor((float(frag.x) - phX) / stepX)) - cx0;
    int cellY = int(floor((float(frag.y) - phY) / stepY)) - cy0;
    fragColor0 = vec4(texelFetch(u_image0, ivec2(cellX, cellY), 0).rgb, 1.0);
}
